export { default as SAffix } from './affix.vue';

export type * from '@soybeanjs/headless/affix';
export type * from './types';

import type { AffixCompactEmits, AffixCompactProps, AffixUi } from '@soybeanjs/headless/affix';
import type { ClassValue } from '@soybeanjs/headless/types';

/**
 * Properties for the Affix component.
 */
export interface AffixProps extends AffixCompactProps {
  /**
   * Additional class names to apply to the content element.
   */
  class?: ClassValue;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<AffixUi>;
}

/**
 * Events for the Affix component.
 */
export type AffixEmits = AffixCompactEmits;

// @unocss-include
import { scv } from '@soybeanjs/cva';

export const affixVariants = scv({
  slots: {
    root: '',
    placeholder: '',
    content: 'data-[state=fixed]:z-50'
  }
});
